# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import pymysql
import json

def search_mysql(request):
    params = json.loads(request.data)

    # Connect to Cloud SQL database
    conn = pymysql.connect(
        host='<YOUR_HOST>',
        user='<YOUR_USER>',
        password='<YOUR_PASSWORD>',
        database='<YOUR_DATABASE>'
    )

    # Build dynamic SQL query from request parameters
    sql = "SELECT * FROM `products` WHERE 1=1"
    filters = []
    for key, value in params.items():
        filters.append(f"`{key}` = '{value}'")

    if filters:
        sql += " AND " + " AND ".join(filters)

    # Execute the query
    cursor = conn.cursor()
    cursor.execute(sql)

    # Fetch results
    results = cursor.fetchall()

    # Close database connection
    conn.close()

    # Return results as JSON
    return json.dumps(results)